INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('fire-eq-tech-moex-01085', 'fire-eq-tech', 'fire-eq-tech-moex-101-d69d8efd', 'sub-fire-eq-tech-02', NULL, 'single_choice', '依據「公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法」規定，室內儲存場所儲存第五類 公共危險物品之有機過氧化物，儲存倉庫應以分隔牆區劃，每一區劃面積應在A平方公尺以下；儲 存倉庫窗戶距離地板應在B公尺以上，設於同一壁面窗戶之總面積不得超過該壁面面積之C分之一， 且每一窗戶之面積不得超過D平方公尺，請問前述A，B，C，D為何？', '["500，1.5，100，0.5", "150，2，80，0.4", "130，1.5，60，0.5", "100，1，50，0.5"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:28+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01086', 'fire-eq-tech', 'fire-eq-tech-moex-101-d69d8efd', 'sub-fire-eq-tech-02', NULL, 'single_choice', '依「各類場所消防安全設備設置標準」規定，集會堂之觀眾席設有固定座部分，且撒水頭裝置面高 度在多少公尺以上者，得免設撒水頭？', '["八", "六", "五", "四"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:28+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01087', 'fire-eq-tech', 'fire-eq-tech-moex-101-d69d8efd', 'sub-fire-eq-tech-02', NULL, 'single_choice', '依據「消防安全設備檢修專業機構管理辦法」有關消防安全設備檢修專業機構之監督及管理規定， 下列敘述何者錯誤？', '["檢修機構應置有專任之消防設備師及消防設備士合計達十人以上，其中消防設備師至少二人", "檢修機構應備置檢修場所清冊及相關檢修報告，並至少保存五年", "檢修機構合格證書記載事項變更時，應於三十日內向內政部申請變更登記", "檢修機構聘用、資遣、解聘消防設備師或消防設備士，應於二十日內，報請內政部備查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:28+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01088', 'fire-eq-tech', 'fire-eq-tech-moex-101-d69d8efd', 'sub-fire-eq-tech-02', NULL, 'single_choice', '消防設備師依「緊急電源容量計算基準」核算供消防安全設備所須之緊急電源容量後，應以書面知 會電機技師供納入整合緊急發電系統設計容量考量，電機技師於接獲前揭消防用緊急電源容量計算 結果資料，應於A日內確認有無影響建築整體緊急發電設備設計之虞，並以書面通知知會之消防設 備師，逾B日未通知時視為無意見，請問前述A，B為何？', '["60，30", "30，15", "15，10", "7，7"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:28+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01089', 'fire-eq-tech', 'fire-eq-tech-moex-101-d69d8efd', 'sub-fire-eq-tech-02', NULL, 'single_choice', '依「滅火器藥劑更換及充填作業規定」，下列敘述何者錯誤？', '["經營滅火器藥劑更換及充填作業廠商應有專任符合消防法規定之消防專技人員（如消防設備師、 消防設備士或暫行從事消防安全設備裝置檢修人員）至少一人，且不得同時任職於其他工廠或公司 （行號）", "製造日期超過十年或無法辨識製造日期之乾粉滅火器，應予報廢，非經水壓測試合格，不得再行 更換及充填藥劑", "重新充填滅火藥劑後之滅火器，於充填完成時其噴射性能須能噴射所充填滅火劑容量或重量90% 以上之量", "重新更換藥劑及充填後之滅火器，應於滅火器瓶頸加裝檢修環，檢修環材質以一體成型之硬質無 縫塑膠、壓克力或鐵環製作，且內徑不得大於滅火器瓶口5 mm"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:28+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01090', 'fire-eq-tech', 'fire-eq-tech-moex-101-d69d8efd', 'sub-fire-eq-tech-02', NULL, 'single_choice', '依「各類場所消防安全設備檢修及申報作業基準」有關簡易自動滅火設備之性能檢查規定，加壓式 滅火藥劑儲存容器之加壓用氣體容器等氣體量檢查方法為以手旋轉加壓用氣體容器，將容器取下， 將容器置於計量器上，測定其總重量，總重量應比標示重量不少於多少公克？', '["14.2", "12.5", "10.5", "8.5"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:28+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01091', 'fire-eq-tech', 'fire-eq-tech-moex-101-d69d8efd', 'sub-fire-eq-tech-02', NULL, 'single_choice', '依「各類場所消防安全設備檢修及申報作業基準」有關消防專用蓄水池檢查規定，下列敘述何者錯誤？', '["進水管投入孔及採水口外觀檢查周圍狀況判定方法為消防車能到達二公尺以內，且使用上應無障礙", "幫浦性能檢查方法先將幫浦吐出側之制水閥關閉之後，使幫浦啟動，然後緩緩的打開性能測試用 配管之制水閥，由流量計及壓力表確認額定負荷運轉及全開點時之性能", "呼水裝置之減水警報裝置性能檢查判定方法為當水量減少至三分之二前應發出警報", "幫浦之性能檢查時除需操作啟動檢查性能外，其餘均需先行切斷電源"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:28+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01092', 'fire-eq-tech', 'fire-eq-tech-moex-101-d69d8efd', 'sub-fire-eq-tech-02', NULL, 'single_choice', '依「各類場所消防安全設備檢修及申報作業基準」規定，下列敘述何者錯誤？', '["各類場所之管理權人應委託檢修專業機構或消防法第7條規定之人員辦理檢修，並於檢修完成後 二十日內，分別填具消防安全設備檢修申報表及檢附消防安全設備檢修報告書，向當地消防機關 申報", "建築物依其用途及管理情形，採整棟申報方式申報檢修結果者，有供甲類用途使用者，視同甲類 場所辦理", "未申領使用執照或未依使用執照用途之違規使用場所，應以其實際用途，辦理檢修申報", "經消防機關會勘通過且依建築法規定取得使用執照、室內裝修許可之合法場所，自取得使用執照 或審查合格證明日期起計算，甲類場所距申報截止日期在六個月以內者，當次免辦理檢修申報"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:28+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01093', 'fire-eq-tech', 'fire-eq-tech-moex-101-d69d8efd', 'sub-fire-eq-tech-02', NULL, 'single_choice', '依「建築法」規定，下列敘述何者正確？', '["直轄市、縣（市）（局）主管建築機關應自收到申請拆除執照應備之申請書之日起十日內審查完 竣，合於規定者，發給拆除執照", "機械遊樂設施經營者應定期委託依法開業之相關專業技師、建築師或經中央主管建築機關指定之 檢查機構、團體實施安全檢查。安全檢查之次數，由該管直轄市、縣（市）主管建築機關定之， 每年不得少於一次", "起造人自領得建造執照或雜項執照之日起，應於六個月內開工；起造人因故不能於前項期限內開 工時，應敘明原因，申請展期一次，期限為三個月", "建築工程完竣後，應由起造人會同承造人及監造人申請使用執照。直轄市、縣（市）（局）主管 建築機關應自接到申請之日起，十日內派員查驗完竣。但供公眾使用建築物之查驗期限，得展延 為三十日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:28+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-01094', 'fire-eq-tech', 'fire-eq-tech-moex-101-d69d8efd', 'sub-fire-eq-tech-02', NULL, 'single_choice', '依「建築技術規則」有關地下建築物之緩衝區規定，下列敘述何者錯誤？', '["緩衝區與連接之地下建築物、地下運輸系統及建築物之地下層間應以具有一小時以上防火時效之 牆壁、防火門窗等防火設備及該層防火構造之樓地板區劃分隔", "連接緩衝區二側之連接出入口，總寬度均應在三公尺以上，六公尺以下，且任一出入口淨寬度不 得小於一點五公尺", "緩衝區面積之百分之二十以上應挑空至地面層", "緩衝區內專供通行及緊急避難使用，不得有營業行為；牆壁得以耐燃一級材料設置嵌入式廣告物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:28+00:00", "source_pdf_sha1": "4dd869ef979d", "answer_pdf_sha1": "c365457e9b88", "source_family": "moex-gov-tw", "moex": {"exam_code": "101070", "c": "901", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "101", "exam_name": "101年專技驗船師第1次食品技師、消防設備人員地政士專責報關人員保險人員、特考語言聽力牙體考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL)
